#include <iostream>
#include <vector>
#include <string>

using namespace std;

class Trie {
public:
    vector<string> words;

    void insert(string word)
    {
        words.push_back(word);
    }

    bool search(string word)
    {
        for (auto &w : words) if (w == word) return true;
        return false;
    }

    bool startsWith(string prefix)
    {
        for (auto &w : words)
            if (w.size() >= prefix.size() && w.substr(0, prefix.size()) == prefix) return true;
        return false;
    }
};

int main()
{
    Trie trie;
    trie.insert("apple");
    cout << boolalpha << trie.search("apple") << ", ";
    cout << trie.search("app") << ", ";
    cout << trie.startsWith("app") << ", ";
    trie.insert("app");
    cout << trie.search("app");

    return 0;
}

#include <iostream>
#include <string>
#include <unordered_map>

using namespace std;

struct TrieNode {
    unordered_map<char, TrieNode*> children;
    bool isEndOfWord = false;
};

class Trie {
public:
    TrieNode* root;

    Trie()
    {
        root = new TrieNode();
    }

    void insert(string word)
    {
        TrieNode* node = root;
        for (char c : word)
        {
            if (node->children.find(c) == node->children.end())
                node->children[c] = new TrieNode();
            node = node->children[c];
        }
        node->isEndOfWord = true;
    }

    TrieNode* findNode(string s)
    {
        TrieNode* node = root;
        for (char c : s)
        {
            if (node->children.find(c) == node->children.end()) return nullptr;
            node = node->children[c];
        }
        return node;
    }

    bool search(string word)
    {
        TrieNode* node = findNode(word);
        return node != nullptr && node->isEndOfWord;
    }

    bool startsWith(string prefix)
    {
        return findNode(prefix) != nullptr;
    }
};

int main()
{
    Trie trie;
    trie.insert("apple");
    cout << boolalpha << trie.search("apple") << ", ";
    cout << trie.search("app") << ", ";
    cout << trie.startsWith("app") << ", ";
    trie.insert("app");
    cout << trie.search("app");

    return 0;
}

